ihtx.tagscript:
{set:string|{substring:{args}|{indexof:{arg:5}|{args}}}}

{set:code|load {media}

vidlen=$(ffprobe -i $FILE_1 -show_entries format=duration -v quiet -of csv="p=0")
dur=$(awk -v vidlen="$vidlen" 'BEGIN{bracketleft} printf {arg:1} {bracketright}')

ffmpeg -loglevel error -i "https://file.garden/aTXso15ukD3mnuPI/resized.mp4" -vf scale=4:4,setsar=1:1,"geq=r=128:g=128:b=128" -pix_fmt yuv420p -preset ultrafast -an -t 0.03 a.mp4

ffmpeg -loglevel error -y -stream_loop -1 -i $FILE_1 -c:v libx264 -preset ultrafast -b:v 16M -c:a flac -t $dur -movflags +faststart 0.mp4

# Set variables
extension={if:{arg:4}|=|default|then:$(basename ${bracketleft}FILE_1##*.{bracketright})|else:'{arg:4}'}
sr=$(ffprobe -v error -select_streams a:0 -show_entries stream=sample_rate -of default=nokey=1:noprint_wrappers=1 0.mp4)
fr=$(ffprobe -v error -select_streams v:0 -show_entries stream=r_frame_rate -of default=nokey=1:noprint_wrappers=1 0.mp4)
d=$(ffprobe -i 0.mp4 -show_entries format=duration -v quiet -of csv="p=0")
w=$(ffprobe -v error -select_streams v:0 -show_entries stream=width -of default=nw=1:nk=1 0.mp4)
h=$(ffprobe -v error -select_streams v:0 -show_entries stream=height -of default=nw=1:nk=1 0.mp4)
fc=$(ffprobe -v error -select_streams v:0 -show_entries stream=nb_frames -of default=nokey=1:noprint_wrappers=1 0.mp4)

output='./output/icfplus.'$extension

# Render each export
if [ "{arg:2}" == "true" -o "{arg:2}" == "yes" ]; then
   ffmpeg -loglevel error -y -i "0.mp4" {get:string} -movflags +faststart 1.{arg:3}
   for i in $(seq 1 1 {abs:{arg:0}}); do
      ffmpeg -loglevel error -y -i "$i.{arg:3}" {get:string} -movflags +faststart $((i+1)).{arg:3}
   done
else
   ffmpeg -loglevel error -y -stream_loop 1 -i "0.mp4" {get:string} -t $dur -movflags +faststart 1.{arg:3}
   for i in $(seq 1 1 {abs:{arg:0}}); do
      ffmpeg -loglevel error -y -stream_loop 1 -i "$i.{arg:3}" {get:string} -t $dur -movflags +faststart $((i+1)).{arg:3}
   done
fi

# Build concat list
if [ {arg:0} -lt 0 ]; then
   for i in $(seq {abs:{arg:0}} -1 1); do
      echo "file '$i.{arg:3}'"
   done
else
   for i in $(seq 1 1 {abs:{arg:0}}); do
      echo "file '$i.{arg:3}'"
   done
fi >> concat.txt

# Concat all exports
case "{arg:4}" in
   "mkv") ffmpeg -loglevel error -y -f concat -safe 0 -i "concat.txt" -c:v mpeg2video -q:v 1 -c:a flac -pix_fmt yuv420p -bufsize 64M -movflags +faststart $output;;
   "mxf") ffmpeg -loglevel error -y -f concat -safe 0 -i "concat.txt" -c:v mpeg2video -qscale 1 -qmin 1 -c:a pcm_s16le -ar 48000 -pix_fmt yuv420p -bufsize 64M -movflags +faststart $output;;
   "mov") ffmpeg -loglevel error -y -f concat -safe 0 -i "concat.txt" -c:v libx264 -profile:v high422 -level:v 5 -tune zerolatency -q:v 1 -crf 30 -preset superfast -c:a aac -q:a 10 -b:a 192K -aac_coder fast -pix_fmt yuv420p -bufsize 64M -movflags +faststart $output;;
   "mp4") ffmpeg -loglevel error -y -f concat -safe 0 -i "concat.txt" -c:v libx264 -profile:v high422 -level:v 5 -tune zerolatency -q:v 1 -crf 30 -preset superfast -c:a flac -pix_fmt yuv420p -bufsize 64M -movflags +faststart $output;;
   avi) ffmpeg -loglevel error -y -f concat -safe 0 -i "concat.txt" -c:v mpeg2video -c:a flac -pix_fmt yuv420p -movflags +faststart $output;;
   *) ffmpeg -loglevel error -y -f concat -safe 0 -i "concat.txt" -pix_fmt yuv420p -bufsize 64M -movflags +faststart $output;;
esac

rm -f *.{arg:3} concat.txt a.mp4 b.png 0.mp4}

